import modal
from collections import Counter

app = modal.App("batch-word-freq")

image = modal.Image.debian_slim()


@app.function(image=image)
def count_words(sentence: str) -> dict:
    words = sentence.lower().split()
    return dict(Counter(words))


@app.local_entrypoint()
def main():
    sentences = [
        "the quick brown fox jumps over the lazy dog",
        "to be or not to be that is the question",
        "all that glitters is not gold",
        "the quick brown fox ran over the hill",
        "be yourself everyone else is already taken",
    ]

    results = list(count_words.map(sentences))

    combined: dict[str, int] = {}
    for freq_map in results:
        for word, count in freq_map.items():
            combined[word] = combined.get(word, 0) + count

    output_dict = modal.Dict.from_name("batch-word-freq-output", create_if_missing=True)
    output_dict["frequencies"] = combined
    output_dict["sentence_count"] = len(sentences)

    print(f"Processed {len(sentences)} sentences.")
    print(f"Combined word frequencies: {combined}")
